{
  "aim_act": {
    "signed_into_law": "YYYY",
    "phasedown_2024_pct": <number>,
    "phasedown_2029_pct": <number>,
    "phasedown_2036_pct": <number>
  },
  "refrigerants": {
    "R-410A": { "gwp": <number>, "ashrae_safety_class": "A1" },
    "<Alternative_1>": { "gwp": <number>, "ashrae_safety_class": "..." },
